if @delete_yn = 1 begin
  declare @c bit
  exec @@sysDatabaseName..FastBusiness$System$CheckSum @@userID, @$chkpass, 0, @c output
  if @c = 0 begin
    select 'cpass' as field, @$updateDeny as message, replace(@$script, '%s', 'cpass') as script
    return
  end
end

select @id = isnull(max(id) + 1, 1) from @@table
select @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID, @ngay_tao = convert(varchar, getdate(), 111)







update @@table set ma_so = left(newid(),8), database_nguon = '&DatabaseSource;', database_dich = '@@appDatabaseName' where id = @id
