      &OutlineEntry;

function active$DataCopy(f) {
  f.add_onResponseComplete(on$DataCopy$ResponseComplete);
  changeLookupReadonly(f, 'ma_ct', true);
  changeLookupReadonly(f, 'ma_dvcs', true);
  if (f._action != 'View') {
    if (f._action == 'New') {
      validValue(f);
    }
    disableFields(f);
    f.getItem('loai').focus();
    f.setItemValue('kieu_chuyen', '&TransferType;')
  }
}
function close$DataCopy(f) {try {f.remove_onResponseComplete(on$DataCopy$ResponseComplete);} catch (ex) {}}
function on$DataCopy$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Checking':
      break;
    default:
      break;
  }
}

function validFields(f) {
  validValue(f);
  disableFields(f);
}

function onChange$Type(o) {
  validFields(o.parentForm);
}

function onChange$Delete(o) {
  var f = o.parentForm;
  if(f.getItemValue('delete_yn')) {
    f.setItemValues('ngay_xoa0, ngay_xoa2', [f.getItemValue('ngay_ct0'), f.getItemValue('ngay_ct2')]);
    setItemDisable(f, 'ngay_xoa0, ngay_xoa2, cpass', false);
    setItemAllowNulls(f, 'ngay_xoa0, ngay_xoa2, cpass', false);
  }
  else {
    f.setItemValues('ngay_xoa0, ngay_xoa2, cpass', [null, null, null];
    setItemDisable(f, 'ngay_xoa0, ngay_xoa2, cpass', true);
    setItemAllowNulls(f, 'ngay_xoa0, ngay_xoa2, cpass', true);
  }
}

function disableFields(f) {
  var v = f.getItemValue('loai') != '1', v1 = f.getItemValue('delete_yn'), v2 = f.getItemValue('loai') != '2', t1 = 'ngay_ct0, ngay_ct2, ma_ct, ma_dvcs, delete_yn', t2 = 'ngay_tao0, ngay_tao2, ngay_sua0, ngay_sua2', t3 = 'ngay_xoa0, ngay_xoa2, cpass', t4 = 'ngay_ct0, ngay_ct2', t5 = 'dir_list';
  setItemDisable(f, t1, v);
  setItemDisable(f, t2, !v);
  setItemDisable(f, t3, !v1);
  setItemDisable(f, t5, v2);
  setItemAllowNulls(f, t4, v);
  setItemAllowNulls(f, t3, !v1);
}

function validValue(f) {
  var d = new Date();
  if (f.getItemValue('loai') != '1') {
    f.setItemValues('ngay_ct0, ngay_ct2, ngay_xoa0, ngay_xoa2, cpass, delete_yn', [null, null, null, null, null, false]);
  } else {
    f.setItemValues('ngay_tao0, ngay_tao2, ngay_sua0, ngay_sua2, ngay_ct0, ngay_ct2, ngay_xoa0, ngay_xoa2, cpass, delete_yn', [null, null, null, null, d, d, null, null, null, false]);
  }
}

function setItemAllowNulls(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      o.field.AllowNulls = v
      grandNode = o.parentNode.parentNode;
      if (!v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
      else Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
    }
  }
}

function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      var o = f.getItem($func.trim(a[i]));
      if (o.a) $common.setVisible(o.a, !v);
      o.disabled = v;
    }
  }
}

function genHash(o) {
  var f = o.parentForm, p = $func.trim(MD5(o.value));
  f.getItem('chkpass').value = CRC32($func.trim(f._key).substr(0, 8) + p.substr(1, p.length - 2));
}
function checkFieldEntry(f, o, force) {
  if (force) o = f.getItem(o);
  var v = force ? o.value : o.oldValue;
  if (f._checked && !v) {
    f._checked = false;
    $func.hideWait(f.get_id());
    $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), o.field.Label), String.format('revertPassword(\'{0}\', \'\', true); $find(\'{0}\').focus(\'{1}\');', f.get_id(), o.field.Name));
  }
}
function revertPassword(f, name, force) {
  if (force) f = $find(f);
  var o = f.getItem('cpass');
  if (o.oldValue) o.value = o.oldValue;
  f.getItem('cpass').focus();
}



